// ============================================================================
// VtDictionary ‚Üî Python dict
// ============================================================================

/// Convert a Rust `Dictionary` to a Python `dict` (recursive).
pub fn dict_to_py(py: Python<'_>, d: &Dictionary) -> PyResult<PyObject> {
    let dict = PyDict::new(py);
    for (k, v) in d.iter() {
        dict.set_item(k, value_to_py(py, v)?)?;
    }
    Ok(dict.into())
}

/// Convert a Python object to a Rust `Value`.
pub fn py_to_value(obj: &Bound<'_, PyAny>) -> PyResult<Value> {
    if obj.is_none() { return Ok(Value::empty()); }
    // bool before int (Python bool subclasses int)
    if let Ok(b) = obj.extract::<bool>() { return Ok(Value::new(b)); }
    if let Ok(i) = obj.extract::<i64>() {
        if i >= i64::from(i32::MIN) && i <= i64::from(i32::MAX) {
            return Ok(Value::new(i as i32));
        }
        return Ok(Value::new(i));
    }
    if let Ok(f) = obj.extract::<f64>() { return Ok(Value::from_f64(f)); }
    if let Ok(s) = obj.extract::<String>() { return Ok(Value::new(s)); }
    if let Ok(d) = obj.downcast::<PyDict>() {
        return Ok(Value::from_dictionary(py_dict_to_dict(d)?.to_hash_map()));
    }
    Ok(Value::empty())
}

fn py_dict_to_dict(d: &Bound<'_, PyDict>) -> PyResult<Dictionary> {
    let mut dict = Dictionary::new();
    for (k, v) in d.iter() {
        let key: String = k.extract()
            .map_err(|_| PyTypeError::new_err("VtDictionary keys must be strings"))?;
        dict.insert_value(key, py_to_value(&v)?);
    }
    Ok(dict)
}

fn value_to_py(py: Python<'_>, v: &Value) -> PyResult<PyObject> {
    if v.is_empty() { return Ok(py.None()); }
    if let Some(b) = v.get::<bool>()   { return Ok(b.into_py(py)); }
    if let Some(i) = v.get::<i32>()    { return Ok(i.into_py(py)); }
    if let Some(i) = v.get::<i64>()    { return Ok(i.into_py(py)); }
    if let Some(u) = v.get::<u64>()    { return Ok(u.into_py(py)); }
    if let Some(x) = v.get::<f64>()    { return Ok(x.into_py(py)); }
    if let Some(x) = v.get::<f32>()    { return Ok((*x as f64).into_py(py)); }
    if let Some(s) = v.get::<String>() { return Ok(s.into_py(py)); }
    if let Some(t) = v.get::<usd_tf::Token>() { return Ok(t.to_string().into_py(py)); }
    if let Some(d) = v.get::<usd_vt::Dictionary>() { return dict_to_py(py, d); }
    Ok(py.None())
}

/// Python-facing `VtDictionary` ‚Äî wraps `Dictionary` and round-trips as Python dict.
#[pyclass(name = "Dictionary", module = "pxr.Vt")]
#[derive(Clone, Default)]
pub struct PyDictionary { inner: Dictionary }

#[pymethods]
impl PyDictionary {
    #[new]
    #[pyo3(signature = (d = None))]
    fn new(d: Option<&Bound<'_, PyDict>>) -> PyResult<Self> {
        Ok(Self { inner: match d { Some(pd) => py_dict_to_dict(pd)?, None => Dictionary::new() } })
    }

    #[pyo3(name = "AsDict")]
    fn as_dict(&self, py: Python<'_>) -> PyResult<PyObject> { dict_to_py(py, &self.inner) }

    fn __len__(&self) -> usize { self.inner.len() }

    fn __repr__(&self, py: Python<'_>) -> PyResult<String> {
        Ok(format!("Vt.Dictionary({})", dict_to_py(py, &self.inner)?.bind(py)))
    }
    fn __str__(&self, py: Python<'_>) -> PyResult<String> {
        Ok(format!("{}", dict_to_py(py, &self.inner)?.bind(py)))
    }

    fn __getitem__(&self, py: Python<'_>, key: &str) -> PyResult<PyObject> {
        self.inner.get(key)
            .ok_or_else(|| pyo3::exceptions::PyKeyError::new_err(key.to_owned()))
            .and_then(|v| value_to_py(py, v))
    }

    fn __setitem__(&mut self, key: &str, value: &Bound<'_, PyAny>) -> PyResult<()> {
        self.inner.insert_value(key.to_owned(), py_to_value(value)?);
        Ok(())
    }

    fn __contains__(&self, key: &str) -> bool { self.inner.contains_key(key) }
    fn __eq__(&self, other: &Self) -> bool { self.inner == other.inner }
    fn __ne__(&self, other: &Self) -> bool { self.inner != other.inner }

    fn keys(&self) -> Vec<String> { self.inner.keys().map(|k| k.clone()).collect() }
}

// ============================================================================
// Module registration
// ============================================================================

/// Register all `pxr.Vt` classes.
pub fn register(py: Python<'_>, m: &Bound<'_, PyModule>) -> PyResult<()> {
    let _ = py;

    m.add_class::<PyValue>()?;
    m.add_class::<PyDictionary>()?;

    // Scalar arrays
    m.add_class::<PyBoolArray>()?;
    m.add_class::<PyUCharArray>()?;
    m.add_class::<PyShortArray>()?;
    m.add_class::<PyUShortArray>()?;
    m.add_class::<PyIntArray>()?;
    m.add_class::<PyUIntArray>()?;
    m.add_class::<PyInt64Array>()?;
    m.add_class::<PyUInt64Array>()?;
    m.add_class::<PyFloatArray>()?;
    m.add_class::<PyDoubleArray>()?;
    m.add_class::<PyHalfArray>()?;

    // String / Token arrays
    m.add_class::<PyStringArray>()?;
    m.add_class::<PyTokenArray>()?;

    // Vec arrays
    m.add_class::<PyVec2fArray>()?;
    m.add_class::<PyVec3fArray>()?;
    m.add_class::<PyVec4fArray>()?;
    m.add_class::<PyVec2dArray>()?;
    m.add_class::<PyVec3dArray>()?;
    m.add_class::<PyVec4dArray>()?;
    m.add_class::<PyVec2iArray>()?;
    m.add_class::<PyVec3iArray>()?;
    m.add_class::<PyVec4iArray>()?;

    // Matrix arrays
    m.add_class::<PyMatrix4dArray>()?;
    m.add_class::<PyMatrix4fArray>()?;

    // Iterators (must be registered so PyO3 can handle iterator protocol)
    m.add_class::<VtBoolIter>()?;
    m.add_class::<VtI8Iter>()?;
    m.add_class::<VtU8Iter>()?;
    m.add_class::<VtI16Iter>()?;
    m.add_class::<VtU16Iter>()?;
    m.add_class::<VtI32Iter>()?;
    m.add_class::<VtU32Iter>()?;
    m.add_class::<VtI64Iter>()?;
    m.add_class::<VtU64Iter>()?;
    m.add_class::<VtF32Iter>()?;
    m.add_class::<VtF64Iter>()?;
    m.add_class::<VtStringIter>()?;

    Ok(())
}
